import React, { useState, useEffect } from 'react';
import bridge from '@vkontakte/vk-bridge';
import { ScreenSpinner, AdaptivityProvider, AppRoot, ConfigProvider, SplitLayout, SplitCol, ModalRoot } from '@vkontakte/vkui';
import '@vkontakte/vkui/dist/vkui.css';

import Home from './panels/Home';

const App = () => {
	const [fetchedUser, setUser] = useState(null);
	const [popout, setPopout] = useState(<ScreenSpinner size='large' />);
	const [modal, setModal] = useState(null);
	const [modalError, setModalError] = useState([]);
	const [modalsList, setModalsList] = useState(null);
	const [animate, setAnimate] = useState(false);
	const [openGroupPage, setOpenGroupPage] = useState(1);
	const [openAccessPage, setOpenAccessPage] = useState(1);

	const [resultUrl, setResultUrl] = useState("");
	const [resultImageUrlPost, setResultImageUrlPost] = useState("");
	const [urlPublication, setUrlPublication] = useState("");
	const [textPublication, setTextPublication] = useState("");
	const [textAlbum, setTextAlbum] = useState("");

	useEffect(() => {
		async function fetchData() {
			const user = await bridge.send('VKWebAppGetUserInfo');
			setUser(user);
		}
		fetchData();
	}, []);

	const panels = Home({ fetchedUser, setPopout ,setModalError, setModal, setModalsList, setAnimate, openGroupPage, setOpenGroupPage, openAccessPage, setOpenAccessPage, resultUrl, setResultUrl, resultImageUrlPost, setResultImageUrlPost, urlPublication, setUrlPublication, textPublication, setTextPublication, textAlbum, setTextAlbum })

	const modalsView = (
		<ModalRoot activeModal={modal}>
			{modalError}
			{modalsList}
		</ModalRoot>
	);

	return (
		<ConfigProvider>
			<AdaptivityProvider>
				<AppRoot>
					<SplitLayout popout={popout} modal={modalsView}>
						<SplitCol animate={animate}>
							{panels}
						</SplitCol>
					</SplitLayout>
				</AppRoot>
			</AdaptivityProvider>
		</ConfigProvider>
	);
}

export default App;
